import{_ as a,c as t,o as r,ag as i}from"./chunks/framework.dvv-DFtf.js";const p=JSON.parse('{"title":"Cherry Studio 配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/clients/cherry-studio.md","filePath":"guide/clients/cherry-studio.md","lastUpdated":1772163360000}'),d={name:"guide/clients/cherry-studio.md"};function o(l,e,s,h,n,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\clients\\cherry-studio.md for this page in Markdown format</div><h1 id="cherry-studio-配置" tabindex="-1">Cherry Studio 配置 <a class="header-anchor" href="#cherry-studio-配置" aria-label="Permalink to &quot;Cherry Studio 配置&quot;">​</a></h1><p><a href="https://cherry-ai.com" target="_blank" rel="noreferrer">Cherry Studio</a> 是一款优秀的跨平台 AI 客户端，支持多种模型供应商。</p><h2 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h2><ol><li>打开 Cherry Studio 设置</li><li>选择「API 提供商」</li><li>点击「添加自定义供应商」</li><li>填写以下信息：</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>名称</td><td>Lurus API</td></tr><tr><td>API Base URL</td><td><code>https://api.lurus.cn/v1</code></td></tr><tr><td>API Key</td><td>你的 API Key (sk-xxx)</td></tr></tbody></table><ol start="5"><li>保存配置</li></ol><h2 id="快速配置链接" tabindex="-1">快速配置链接 <a class="header-anchor" href="#快速配置链接" aria-label="Permalink to &quot;快速配置链接&quot;">​</a></h2><p>点击以下链接可快速导入配置：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cherrystudio://providers/api-keys?v=1&amp;data={cherryConfig}</span></span></code></pre></div><p>将 <code>{cherryConfig}</code> 替换为你的配置信息。</p><h2 id="选择模型" tabindex="-1">选择模型 <a class="header-anchor" href="#选择模型" aria-label="Permalink to &quot;选择模型&quot;">​</a></h2><p>配置完成后，在 Cherry Studio 中选择 Lurus API 作为供应商，即可使用所有支持的模型。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="连接失败" tabindex="-1">连接失败？ <a class="header-anchor" href="#连接失败" aria-label="Permalink to &quot;连接失败？&quot;">​</a></h3><ul><li>检查 API Key 是否正确</li><li>确认网络连接正常</li><li>检查 Base URL 是否正确</li></ul><h3 id="模型列表为空" tabindex="-1">模型列表为空？ <a class="header-anchor" href="#模型列表为空" aria-label="Permalink to &quot;模型列表为空？&quot;">​</a></h3><p>尝试在设置中手动刷新模型列表，或手动输入模型名称如 <code>deepseek-chat</code>。</p>',18)])])}const y=a(d,[["render",o]]);export{p as __pageData,y as default};
